关于libuv Event Loop的各阶段执行顺序，以下描述正确的是？

请分析以下代码的输出顺序：
```javascript
const fs = require('fs');

// 场景1：I/O回调中setImmediate vs setTimeout
fs.readFile(__filename, () => {
  setTimeout(() => console.log('timeout'), 0);
  setImmediate(() => console.log('immediate'));
});

// 场景2：主模块中setImmediate vs setTimeout
setTimeout(() => console.log('timeout1'), 0);
setImmediate(() => console.log('immediate1'));
```

关于process.nextTick和队列饥饿问题，以下分析正确的是？

```javascript
// 代码示例
function recursiveNextTick(count) {
  if (count > 0) {
    process.nextTick(() => {
      console.log('nextTick:', count);
      recursiveNextTick(count - 1);
    });
  }
}

setTimeout(() => console.log('timeout executed'), 0);
setImmediate(() => console.log('immediate executed'));
recursiveNextTick(100000);
```

