关于Stream pipe的错误处理，以下最佳实践是？

```javascript
const fs = require('fs');

// 错误处理方式1
function method1() {
  return fs.createReadStream('source.txt')
    .pipe(fs.createWriteStream('dest.txt'));
}

// 错误处理方式2
function method2() {
  const source = fs.createReadStream('source.txt');
  const dest = fs.createWriteStream('dest.txt');
  source.on('error', console.error);
  dest.on('error', console.error);
  return source.pipe(dest);
}

// 错误处理方式3
function method3() {
  const source = fs.createReadStream('source.txt');
  const dest = fs.createWriteStream('dest.txt');
  source.pipe(dest).on('error', console.error);
}
```

